VALUES
  ('aboriginal-0a2fc18c-moex-00053', 'aboriginal-0a2fc18c', 'aboriginal-0a2fc18c-moex-113-d3ff7f6b', 'sub-aboriginal-0a2fc18c-03', NULL, 'single_choice', '假設小樹在有限的所得限制下規劃兩個期間的消費。若他在第一期為借款者（borrower），當市場 利率上升時，下列敘述何者正確？', '["所得效果讓小樹第一期消費減少", "跨期替代效果讓小樹第一期消費增加", "當跨期替代效果強過所得效果，小樹第一期儲蓄增加", "當跨期替代效果強過所得效果，小樹第一期消費增加"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:40+00:00", "source_pdf_sha1": "685206a260cd", "answer_pdf_sha1": "12d6a2396830", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "408", "s": "1107", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "經建行政"}'::jsonb, NULL),
  ('aboriginal-0a2fc18c-moex-00054', 'aboriginal-0a2fc18c', 'aboriginal-0a2fc18c-moex-113-d3ff7f6b', 'sub-aboriginal-0a2fc18c-03', NULL, 'single_choice', '某經濟體的生產函數為Cobb-Douglas型態為Y=K1-αLα，其中Y為產出、K為資本投入、L為勞 動投入，且0≦α≦1。下列敘述何者錯誤？', '["該生產函數具有固定規模報酬（constantreturnstoscale）特性", "該生產函數具有資本邊際產量遞減（diminishingreturnstocapital）特性", "該生產函數勞動邊際產量遞減（diminishingreturnstolabor）特性", "該生產函數具有零階齊次（homogeneousofdegreezero）特性"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:40+00:00", "source_pdf_sha1": "685206a260cd", "answer_pdf_sha1": "12d6a2396830", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "408", "s": "1107", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "經建行政"}'::jsonb, NULL),
  ('aboriginal-0a2fc18c-moex-00055', 'aboriginal-0a2fc18c', 'aboriginal-0a2fc18c-moex-113-d3ff7f6b', 'sub-aboriginal-0a2fc18c-03', NULL, 'single_choice', '某廠商使用勞動與資本兩種生產要素生產產品A，如果廠商使用500單位勞動與2,000單位資本 時發現勞動邊際產出遞增，此時該廠商的：', '["邊際成本遞減", "平均成本遞增", "生產技術進步", "總成本遞減"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:40+00:00", "source_pdf_sha1": "685206a260cd", "answer_pdf_sha1": "12d6a2396830", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "408", "s": "1107", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "經建行政"}'::jsonb, NULL),
  ('aboriginal-0a2fc18c-moex-00056', 'aboriginal-0a2fc18c', 'aboriginal-0a2fc18c-moex-113-d3ff7f6b', 'sub-aboriginal-0a2fc18c-03', NULL, 'single_choice', '有關完全競爭市場的長期分析，下列敘述何者正確？', '["個別廠商的利潤會大於零", "個別廠商利潤極大化下的最適產量，其平均成本會高於邊際成本", "個別廠商利潤極大化下的最適產量，其平均成本會等於邊際成本", "個別廠商利潤極大化下的最適產量，其平均成本會小於邊際成本"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:40+00:00", "source_pdf_sha1": "685206a260cd", "answer_pdf_sha1": "12d6a2396830", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "408", "s": "1107", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "經建行政"}'::jsonb, NULL),
  ('aboriginal-0a2fc18c-moex-00057', 'aboriginal-0a2fc18c', 'aboriginal-0a2fc18c-moex-113-d3ff7f6b', 'sub-aboriginal-0a2fc18c-03', NULL, 'single_choice', '若追求利潤極大的主題樂園採用的是兩部定價法（two-parttariff）訂價策略，亦即消費者在進園時 先付一個入園費，之後每玩一項設施再另付一個費用。比起另一種一票玩到底的「單一訂價模式」， 下列何者不是兩部定價法的結果？', '["廠商的利潤更高", "消費者的效用更高", "消費者剩餘更低", "生產者剩餘更高"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:40+00:00", "source_pdf_sha1": "685206a260cd", "answer_pdf_sha1": "12d6a2396830", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "408", "s": "1107", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "經建行政"}'::jsonb, NULL),
  ('aboriginal-0a2fc18c-moex-00058', 'aboriginal-0a2fc18c', 'aboriginal-0a2fc18c-moex-113-d3ff7f6b', 'sub-aboriginal-0a2fc18c-03', NULL, 'single_choice', '假設在一雙占市場裡甲、乙兩廠商可選擇高價格（P ）或是低價格（P ）來競逐市場消費者。下 H L 列的報酬矩陣羅列了各家廠商在不同的價格策略組合下的利潤水準，其中每一矩陣格裡的第一個 數字代表了甲廠商的報酬，第二個數字代表了乙廠商的報酬。若要使{P ,P }成為Nash均衡結果， L L 即甲、乙兩廠商都選擇低價格，下列何者滿足條件？ 乙 P P H L P a,b c,d 甲 H P e,f g,h L', '["g≧e，且h≧d", "g≧c，且h≧f", "g≦e，且 h≦d", "g≦c，且h≦f"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:40+00:00", "source_pdf_sha1": "685206a260cd", "answer_pdf_sha1": "12d6a2396830", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "408", "s": "1107", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "經建行政"}'::jsonb, NULL),
  ('aboriginal-0a2fc18c-moex-00059', 'aboriginal-0a2fc18c', 'aboriginal-0a2fc18c-moex-113-d3ff7f6b', 'sub-aboriginal-0a2fc18c-03', NULL, 'single_choice', '一般均衡分析和部分均衡分析為兩種經濟分析模式，下列敘述何者正確？', '["一般均衡分析假設所有市場皆為完全競爭市場", "部分均衡分析假設僅有部分的市場是完全競爭市場", "一般均衡分析考慮所有市場間的交互影響", "一般均衡分析的模型中，市場價格通常視為外生變數"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:40+00:00", "source_pdf_sha1": "685206a260cd", "answer_pdf_sha1": "12d6a2396830", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "408", "s": "1107", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "經建行政"}'::jsonb, NULL),
  ('aboriginal-0a2fc18c-moex-00060', 'aboriginal-0a2fc18c', 'aboriginal-0a2fc18c-moex-113-d3ff7f6b', 'sub-aboriginal-0a2fc18c-03', NULL, 'single_choice', '假設某一棵果樹每年年底的產值皆為1元，此樹的壽命為無窮長。如果市場年利率永遠都是10%， 則此果樹的總產值在第1年年初的現值為何？', '["1", "11", "111", "無窮大"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:40+00:00", "source_pdf_sha1": "685206a260cd", "answer_pdf_sha1": "12d6a2396830", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "408", "s": "1107", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "經建行政"}'::jsonb, NULL),
  ('aboriginal-0a2fc18c-moex-00061', 'aboriginal-0a2fc18c', 'aboriginal-0a2fc18c-moex-113-d3ff7f6b', 'sub-aboriginal-0a2fc18c-03', NULL, 'single_choice', '連續假期常發生高速公路嚴重塞車情況，政府採取下列何種政策最能減少外部性所引起的社會福 利下降？', '["停收高速公路通行費", "封閉一半高速公路出入口", "增加員警取締違規", "調升高速公路通行費"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:40+00:00", "source_pdf_sha1": "685206a260cd", "answer_pdf_sha1": "12d6a2396830", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "408", "s": "1107", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "經建行政"}'::jsonb, NULL),
  ('aboriginal-0a2fc18c-moex-00062', 'aboriginal-0a2fc18c', 'aboriginal-0a2fc18c-moex-113-d3ff7f6b', 'sub-aboriginal-0a2fc18c-03', NULL, 'single_choice', '下列何者非為政府失靈的原因？', '["缺乏競爭，導致無效率", "假政府之名，行個人效用極大化之實", "政府支出的國民所得彈性大於一", "少數服從多數使政策難以盡善盡美，或使政策錯誤"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:40+00:00", "source_pdf_sha1": "685206a260cd", "answer_pdf_sha1": "12d6a2396830", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "408", "s": "1107", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "經建行政"}'::jsonb, NULL)
